import{_ as s,c as a,o as n,ag as l}from"./chunks/framework.JBGcyr1I.js";const c=JSON.parse('{"title":"Annoy 简介：轻量级近似最近邻库","description":"","frontmatter":{},"headers":[],"relativePath":"Annoy/chapter1/Annoy 介绍.md","filePath":"Annoy/chapter1/Annoy 介绍.md","lastUpdated":1763541896000}'),e={name:"Annoy/chapter1/Annoy 介绍.md"};function t(h,i,p,r,o,k){return n(),a("div",null,[...i[0]||(i[0]=[l(`<h1 id="annoy-简介-轻量级近似最近邻库" tabindex="-1">Annoy 简介：轻量级近似最近邻库 <a class="header-anchor" href="#annoy-简介-轻量级近似最近邻库" aria-label="Permalink to &quot;Annoy 简介：轻量级近似最近邻库&quot;">​</a></h1><h2 id="_1-轻量级向量检索的先驱-annoy-是什么" tabindex="-1">1. 轻量级向量检索的先驱：Annoy 是什么 <a class="header-anchor" href="#_1-轻量级向量检索的先驱-annoy-是什么" aria-label="Permalink to &quot;1. 轻量级向量检索的先驱：Annoy 是什么&quot;">​</a></h2><h3 id="项目背景与发展历程" tabindex="-1">项目背景与发展历程 <a class="header-anchor" href="#项目背景与发展历程" aria-label="Permalink to &quot;项目背景与发展历程&quot;">​</a></h3><p>Annoy（Approximate Nearest Neighbors Oh Yeah）由Spotify于2013年开源，是向量检索领域的早期先驱之一。该项目诞生于Spotify音乐推荐系统的实际需求，旨在为数百万首歌曲的特征向量提供高效的相似性搜索能力。作为一个专注于解决实际工程问题的项目，Annoy体现了&quot;简单即美&quot;的设计哲学，通过极简的API和高效的算法实现，成为了轻量级向量检索的代表性解决方案。</p><p>Spotify的工程师Erik Bernhardsson在设计Annoy时面临的核心挑战是：如何在有限的内存和计算资源下，为大规模音乐库提供实时的相似歌曲推荐。传统的暴力搜索方法在面对百万级数据时性能急剧下降，而当时市面上缺乏成熟的向量检索解决方案。这种实际需求驱动了Annoy的诞生，也决定了其轻量级、高性能的技术特色。</p><p>经过十年的发展，Annoy已经成为Python生态系统中最受欢迎的向量检索库之一，在GitHub上获得了超过14k个星标。其简洁的设计和卓越的性能使其被广泛应用于推荐系统、自然语言处理、计算机视觉等多个领域。</p><p>和 Milvus、Faiss 这类“重量级”向量数据库/库相比，Annoy 的定位更接近一个 <strong>单机检索引擎组件</strong>：</p><ul><li>只做一件事：在给定的静态向量集合上，提供非常快的相似向量检索</li><li>提供极简 API，易于嵌入到现有 Python/C++ 服务中</li><li>通过 mmap 索引文件实现 <strong>低内存占用 + 多进程共享</strong></li></ul><p>下面是一个最小示例，感受一下 Annoy 的使用风格：</p><div class="language-python vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> annoy </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AnnoyIndex</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">f </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 40</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 向量维度</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AnnoyIndex(f, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;angular&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 角度距离（等价于余弦相似度）</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 添加 3 个向量</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.add_item(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.add_item(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.add_item(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.9</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.build(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 构建 10 棵随机投影树</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查询与 item 0 最相似的 2 个向量</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(index.get_nns_by_item(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">include_distances</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><blockquote><p>可以看到：没有复杂的 Schema、集合概念，本质上是一个“向量 ID → 向量值”的静态索引。</p></blockquote><h2 id="_2-核心特性与优势" tabindex="-1">2. 核心特性与优势 <a class="header-anchor" href="#_2-核心特性与优势" aria-label="Permalink to &quot;2. 核心特性与优势&quot;">​</a></h2><p>从工程实践角度看，Annoy 的优势主要体现在以下几方面：</p><h3 id="_2-1-极简-api-学习成本低" tabindex="-1">2.1 极简 API，学习成本低 <a class="header-anchor" href="#_2-1-极简-api-学习成本低" aria-label="Permalink to &quot;2.1 极简 API，学习成本低&quot;">​</a></h3><ul><li>核心类只有一个：<code>AnnoyIndex</code></li><li>核心方法也就几组：<code>add_item()</code>、<code>build()</code>、<code>get_nns_by_item()</code>、<code>get_nns_by_vector()</code>、<code>save()</code>、<code>load()</code></li><li>没有复杂的 DDL/查询语言，几乎不需要学习曲线</li></ul><h3 id="_2-2-mmap-只读索引-资源占用极低" tabindex="-1">2.2 mmap + 只读索引，资源占用极低 <a class="header-anchor" href="#_2-2-mmap-只读索引-资源占用极低" aria-label="Permalink to &quot;2.2 mmap + 只读索引，资源占用极低&quot;">​</a></h3><ul><li>索引文件以二进制格式持久化到磁盘</li><li>使用内存映射（mmap）将文件映射到虚拟内存： <ul><li>实际物理内存只按访问需要按页加载</li><li>多个进程可共享同一份索引文件，适合多进程 Web 服务</li></ul></li><li>在 <strong>内存受限</strong>、单机多进程的场景下优势明显</li></ul><h3 id="_2-3-查询延迟极低" tabindex="-1">2.3 查询延迟极低 <a class="header-anchor" href="#_2-3-查询延迟极低" aria-label="Permalink to &quot;2.3 查询延迟极低&quot;">​</a></h3><ul><li>针对中等规模（百万～千万级）数据，在合理参数下可做到 <strong>毫秒级查询</strong></li><li>随机投影树结构让查询复杂度接近 O(log n)</li><li>索引结构针对 CPU cache 友好设计，减少 cache miss</li></ul><h3 id="_2-4-部署与集成简单" tabindex="-1">2.4 部署与集成简单 <a class="header-anchor" href="#_2-4-部署与集成简单" aria-label="Permalink to &quot;2.4 部署与集成简单&quot;">​</a></h3><ul><li>纯用户态库，无外部服务依赖</li><li>Python 直接 <code>pip install annoy</code> 即可使用</li><li>支持 C++、Python、Java、Go 等多语言绑定</li><li>非常适合在现有服务中 <strong>嵌入式集成</strong></li></ul><h2 id="_3-工作原理与算法基础" tabindex="-1">3. 工作原理与算法基础 <a class="header-anchor" href="#_3-工作原理与算法基础" aria-label="Permalink to &quot;3. 工作原理与算法基础&quot;">​</a></h2><p>Annoy 的核心是 <strong>随机投影树（Random Projection Trees）</strong>，属于“基于空间分割”的 ANN 算法。</p><h3 id="_3-1-随机投影树的直观理解" tabindex="-1">3.1 随机投影树的直观理解 <a class="header-anchor" href="#_3-1-随机投影树的直观理解" aria-label="Permalink to &quot;3.1 随机投影树的直观理解&quot;">​</a></h3><p>构建索引时，Annoy 会为同一批向量构建多棵随机投影树：</p><ol><li>每一层随机采样两个向量，构造一条“随机超平面”</li><li>根据向量在该超平面两侧的位置，将向量集划分为左右两部分</li><li>递归分割，直到叶子节点中的向量数低于某个阈值</li></ol><p>多棵树组成一片“森林”：</p><ul><li>单棵树给出一个粗糙的近邻候选集合</li><li>多棵树的结果做合并，能在 <strong>查询精度和速度</strong> 之间取得较好平衡</li></ul><h3 id="_3-2-距离度量" tabindex="-1">3.2 距离度量 <a class="header-anchor" href="#_3-2-距离度量" aria-label="Permalink to &quot;3.2 距离度量&quot;">​</a></h3><p>Annoy 支持多种距离度量：</p><ul><li><code>angular</code>：角度距离，常用于归一化后的文本/推荐向量</li><li><code>euclidean</code>：欧氏距离，常用于图像、几何特征</li><li><code>manhattan</code>：曼哈顿距离</li><li><code>hamming</code>：汉明距离，适合二进制特征</li><li><code>dot</code>：点积</li></ul><p>选择合适的距离度量，是保证检索效果的关键之一。</p><h2 id="_4-典型应用场景" tabindex="-1">4. 典型应用场景 <a class="header-anchor" href="#_4-典型应用场景" aria-label="Permalink to &quot;4. 典型应用场景&quot;">​</a></h2><p>Annoy 非常适合以下类型的业务：</p><ul><li><strong>推荐系统</strong>： <ul><li>音乐、视频、商品推荐</li><li>用户画像相似度检索</li></ul></li><li><strong>内容检索</strong>： <ul><li>文本相似度搜索</li><li>图像特征相似检索</li></ul></li><li><strong>特征匹配与聚类预处理</strong>： <ul><li>先用 Annoy 找到候选近邻，再在小集合上做精确计算或聚类</li></ul></li><li><strong>原型验证与教学实验</strong>： <ul><li>想快速搭一个 ANN Demo，不想搭复杂的向量数据库集群</li></ul></li></ul><blockquote><p>总结一句：<strong>读多写少、数据规模中等、单机为主</strong> 的检索场景里，Annoy 往往是性价比极高的选择。</p></blockquote><h2 id="_5-与-milvus、faiss-等向量数据库的对比" tabindex="-1">5. 与 Milvus、Faiss 等向量数据库的对比 <a class="header-anchor" href="#_5-与-milvus、faiss-等向量数据库的对比" aria-label="Permalink to &quot;5. 与 Milvus、Faiss 等向量数据库的对比&quot;">​</a></h2><p>从定位上看，可以粗略地将几种常见方案分层：</p><ul><li><strong>底层算法库</strong>：Faiss、hnswlib 等</li><li><strong>单机检索组件</strong>：Annoy</li><li><strong>分布式向量数据库</strong>：Milvus、Qdrant、Weaviate 等</li></ul><p>Annoy 和 Milvus/Faiss 的差异可以概括如下：</p><ul><li><strong>与 Faiss 相比</strong>： <ul><li>Faiss 更像“算法实验室”，索引类型极多，支持 GPU、PQ 压缩等</li><li>Annoy 只提供一种主索引（随机投影森林），但 API 极简、部署非常轻量</li></ul></li><li><strong>与 Milvus 相比</strong>： <ul><li>Milvus 提供完备的 Schema、分布式存储、监控、运维能力，适合企业级场景</li><li>Annoy 不关心分布式与存储，只负责在本机文件上做高效 ANN 检索</li></ul></li></ul><p>可以将 Annoy 看作是向量检索技术栈中的 <strong>“轻量级积木”</strong>：</p><ul><li>当只需要在一台机器上做相似度搜索时，用 Annoy 就够了</li><li>当需要可扩展、企业级的能力时，再考虑 Milvus 等向量数据库</li></ul><h2 id="_6-何时优先选择-annoy" tabindex="-1">6. 何时优先选择 Annoy <a class="header-anchor" href="#_6-何时优先选择-annoy" aria-label="Permalink to &quot;6. 何时优先选择 Annoy&quot;">​</a></h2><p>在设计系统架构时，可以用以下经验法则判断是否适合优先使用 Annoy：</p><ul><li>✅ 数据规模在 <strong>百万～千万级</strong>，单机即可容纳</li><li>✅ 写入频率低，数据可以离线批量更新</li><li>✅ 业务以 <strong>低延迟查询</strong> 为主，对一致性、复杂查询语法要求不高</li><li>✅ 希望部署简单，不希望引入额外服务组件</li></ul><p>如果你的系统满足以上大部分条件，那么从 Annoy 入手，往往是 <strong>成本最低、见效最快</strong> 的方案。</p>`,47)])])}const u=s(e,[["render",t]]);export{c as __pageData,u as default};
